/*
*@name CheckUserScreenPermissionAddOns
*@date 21/11/2022
*@author Wilfrid Azariah CAD-IT
*@param navigationMenuDataEntries	INFOTABLE (HPMC.Core.NavigationMenu.DataCollection.Simplified.DS)
*@return INFOTABLE (HPMC.Core.NavigationMenu.DataCollection.Simplified.DS)
*
* [21/11/2022] [Wilfrid Azariah]	Service initialization
*/

/** @type {HPMC.Core.NavigationMenu.DataCollection.Simplified.DS} */
var result;

var loggerBeginning = "["+me.name+":CheckUserScreenPermissionAddOns]";

/****************** SERVICE CODE STARTS HERE *******************/
(function() {
	"use strict";
    // CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.Core.NavigationMenu.DataCollection.Simplified.DS)
    let tempData = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
        dataShapeName: "HPMC.Core.NavigationMenu.DataCollection.Simplified.DS"
    });
    try{
        logger.info(loggerBeginning + " start to filter navigation menu data entries using user permission");
        let newEntry = new Object();
        for (let i = 0; i < navigationMenuDataEntries.length; i++) {
            try {
				// result: INFOTABLE dataShape: ""
				let temp = Things[navigationMenuDataEntries[i].Helper].GetPropertyValues();
                newEntry.TileOrder = navigationMenuDataEntries[i].TileOrder;
                newEntry.IsMashup = navigationMenuDataEntries[i].IsMashup;
                newEntry.TileMashupOrURL = navigationMenuDataEntries[i].TileMashupOrURL;
                newEntry.OpenInNewWindow = navigationMenuDataEntries[i].OpenInNewWindow;
                newEntry.TileIcon = navigationMenuDataEntries[i].TileIcon;
                newEntry.TileBackground = navigationMenuDataEntries[i].TileBackground;
                newEntry.LocalizedTooltip = navigationMenuDataEntries[i].LocalizedTooltip;
                newEntry.LocalizedLabel = navigationMenuDataEntries[i].LocalizedLabel;
                newEntry.LocalizedDescription = navigationMenuDataEntries[i].LocalizedDescription;
                newEntry.Section = navigationMenuDataEntries[i].Section;
                newEntry.Helper = navigationMenuDataEntries[i].Helper;
                tempData.AddRow(newEntry);
            } catch(err) {
            }
        }
    }catch(error){
        logger.error(loggerBeginning + " failed to filter navigation menu data entries using user permission ");
    }
    result = tempData;
}());


/*
 * @name CreateGUID
 * @date 20.08.2020
 * @author Georg Reckendorfer
 * @return a unique ID
 */

var result = "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, function (c) {
    var r = (Math.random() * 16) | 0,
        v = c == "x" ? r : (r & 0x3) | 0x8;
    return v.toString(16);
});


