/** @type {HPMC.Core.NavigationMenu.DataCollection.Simplified.DS} */
var result;

var loggerBeginning = "["+me.name+":DiscardWorldmapForChinaUsersAddOns]";

/****************** SERVICE CODE STARTS HERE *******************/
(function() {
	"use strict";

    // result: STRING
	let serviceUsername = Resources["CurrentSessionInfo"].GetCurrentUser();
    username = (username === null || username === undefined) ? serviceUsername : username;

    // CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.Core.NavigationMenu.DataCollection.Simplified.DS)
    let tempData = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
        dataShapeName: "HPMC.Core.NavigationMenu.DataCollection.Simplified.DS"
    });
    try{
        logger.info(loggerBeginning + " start to filter navigation menu data entries for china users");

        let countryId = Users[username].countryId;
        if (parseInt(countryId) === 1) {
            // Provide your filter using the format as described in the help topic "Query Parameter for Query Services"
            let query = {
             "filters": {
               "type": "NE",
               "fieldName": "TileOrder",
               "value": 20
             }
            };
            var params = {
                t: navigationMenuDataEntries/* INFOTABLE */,
                query: query /* QUERY */
            };
            tempData = Resources["InfoTableFunctions"].Query(params);
        } else {
            tempData = navigationMenuDataEntries;
        }

    }catch(error){
        logger.error(loggerBeginning + " failed to filter navigation menu data entries for china users ");
    }
    result = tempData;
}());


