const CORE_MANAGER_ENTITY = Things["HPMC.Core.Manager"];


const createDateWithOffset = (year, month, day, offset) => {
    let date = new Date(Date.UTC(year, month , day, 0, 0, 0));

    date.setMinutes(date.getMinutes() - offset);

    return date;
};

const result = (() => {
  /**
   * Hint: Date objects created in this services are using the UTC time. When displayed as result in a mashup or
   * in the composer, they will automatically converted into the browser timezone.
   */
  year = parseInt(year);
  month = parseInt(month);
  date = parseInt(date);
  week = parseInt(week);
  const quarterValue = parseInt(quarter);

  let today = new Date();

  if (!category || category === "Customized") return { startDate: dateFrom.setMinutes(dateFrom.getMinutes() - timezoneOffsetCombined), endDate: dateTo.setMinutes(dateTo.getMinutes() - timezoneOffsetCombined) };

  if (category === "Daily") { 
    let startDate = createDateWithOffset(year, month, date, timezoneOffsetCombined);
    let endDate = createDateWithOffset(year, month, date + 1, timezoneOffsetCombined);  
    if (today < endDate) {
    	endDate = today;    
    }

    return {
      startDate: createDateWithOffset(year, month, date, timezoneOffsetCombined),
      endDate: endDate
    };
  }
  if (category === "Weekly") {
    const weekDatesOfMonth = CORE_MANAGER_ENTITY.GetWeeksDropdown({ month: month /* STRING */, year: year /* STRING */ });
    const rowIndex = week - 1;

    const weekStartDate = weekDatesOfMonth[rowIndex].week_start_date.setHours(0,0 - timezoneOffsetCombined, 0,0);
    const weekEndDate = weekDatesOfMonth[rowIndex].week_end_date > today ? today : new Date(weekDatesOfMonth[rowIndex].week_end_date.setHours(23, 59-timezoneOffsetCombined, 59, 99));

    //logger.info("["+me.name + ":GetDateRange] start_date = " + weekDatesOfMonth[rowIndex].week_start_date + ", end_date = " + weekDatesOfMonth[rowIndex].week_end_date + ", weekEndDate = " + weekEndDate);
    //logger.info("["+me.name + ":GetDaterange] + start_date = " +  new Date(weekStartDate) + ", end = " + new Date(weekEndDate));  

      return {
      startDate: weekStartDate,
      endDate: weekEndDate
    };
  }
  if (category === "Monthly") {
    const monthEndDate = new Date(year, month + 1, 0, 23, 59, 59, 99) > today ? today : new Date(year, month + 1, 0, 23, 59 - timezoneOffsetCombined, 59, 99);

    return {
      startDate: new Date(year, month, 1, 0, 0 - timezoneOffsetCombined, 0, 0),
      endDate: monthEndDate
    };
  }

  if (category === "Quarterly") {
    const quarterStart = new Date(today.getFullYear(), quarterValue * 3, 1, 0, 0 - timezoneOffsetCombined, 0, 0);
    const quarterEnd = new Date(today.getFullYear(), (quarterValue * 3) + 3, 0, 23, 59 - timezoneOffsetCombined, 59, 99)  > today ? today 
    : new Date(today.getFullYear(), (quarterValue * 3) + 3, 0, 23, 59 - timezoneOffsetCombined, 59, 99);

    return {
      startDate: quarterStart,
      endDate: quarterEnd
    };
  }
  if (category === "Yearly") {
    const yearlyEndDate = new Date(year, 11, 31, 23, 59 - timezoneOffsetCombined, 59, 99) > today ? today : new Date(year, 11, 31, 23, 59 - timezoneOffsetCombined, 59, 99);

    return {
      startDate: new Date(year, 0, 1, 0, 0 - timezoneOffsetCombined, 0, 0),
      endDate: yearlyEndDate
    };
  }
})();


