const currentLanguage = Resources["CurrentSessionInfo"].GetCurrentUserLanguage();
const translateTitle = (title) => {
    if (!title) return "-";
    let translatedTitle = Resources["RuntimeLocalizationFunctions"].GetEffectiveTokenForLanguage({
    language: currentLanguage /* STRING */,
    token: title.replace(/\[\[(.*?)\]\]/g, '$1') /* STRING */
    });
    if (translatedTitle === "???") {
    translatedTitle = title.replace(/\[\[HPMC\.(.*?)\]\]/g, '$1');
    }
    return translatedTitle;
};

