/**
* @name HasUserRestrictedRole
* @author Christian Krenkel
* @return boolean: true = if current user is part of a restricted Role | false if not
*/

result = (function (){

    const userRoles = Resources["CurrentSessionInfo"].GetCurrentUserGroups();
    const restrictedRoles = me.GetConfigurationTable({tableName: "RestrictedRoles"});

    let restricted = false;

    // Check if user has one of the restricted groups -> restriction > all other!
    userRoles.rows.toArray().some(userRole => {
        restrictedRoles.rows.toArray().some(restrictedRole => {
            if ((userRole.name == restrictedRole.role && !validityScope) || (userRole.name == restrictedRole.role && restrictedRole.modules.includes(validityScope))) {
              restricted = true;
              return true;
            }
        });
        return restricted;
    });

    return restricted;
})();


// Insert init logic of module here (i.e. Setup user permissions, create Things etc.)
let result = false;
/* **************************** Helper functions **************************** */
const addVisibilityPermission = (entityType, entityName, principal, principalType) => {
  entityType[entityName].AddVisibilityPermission({
    principal: principal /* STRING */,
    principalType: principalType /* STRING */
  });
};
const addInstanceVisibilityPermission = (entityType, entityName, principal, principalType) => {
  entityType[entityName].AddInstanceVisibilityPermission({
    principal: principal /* STRING */,
    principalType: principalType /* STRING */
  });
};
const addRunTimePermission = (entityType, entityName, principal, resource, type, principalType) => {
  entityType[entityName].AddRunTimePermission({
    principal: principal /* STRING */,
    allow: true /* BOOLEAN */,
    resource: resource /* STRING */,
    type: type /* STRING */,
    principalType: principalType /* STRING */
  });
};
const addInstanceRunTimePermission = (entityType, entityName, principal, resource, type, principalType) => {
  entityType[entityName].AddInstanceRunTimePermission({
    principal: principal /* STRING */,
    allow: true /* BOOLEAN */,
    resource: resource /* STRING */,
    type: type /* STRING */,
    principalType: principalType /* STRING */
  });
};
const addDesignTimePermission = (entityType, entityName, principal, type, principalType) => {
  entityType[entityName].AddDesignTimePermission({
    principal: principal /* STRING */,
    allow: true /* BOOLEAN */,
    type: type /* STRING */,
    principalType: principalType /* STRING */
  });
};
const createRepositoryFolder = (repositoryName, path, existingPaths) => {
  const params = {
    t: existingPaths /* INFOTABLE */,
    query: {
      filters: {
        type: "EQ",
        fieldName: "path",
        value: "/" + path
      }
    }
    /* QUERY */
  };

  const filteredPaths = Resources["InfoTableFunctions"].Query(params);
  if (filteredPaths.getRowCount() === 0) {
    Things[repositoryName].CreateFolder({
      path: path /* STRING */
    });
  }
};
/* **************************** Constants **************************** */
// Extract the module name from the manager template naming scheme. I.e.
const ORGANIZATION_NAME = "HPMC.Voestalpine.Orga";
const USER_GROUP = "HPMC.Core.Users.UG";
const THING_GROUP = "HPMC.Core.Global.TG";
const MANAGER_THING = me.name;
const DYNAMIC_DATA_PROJECT = me.GetDynamicDataProjectName();

// **************************** INSERT CUSTOM LOGIC HERE **************************** //
try {
  // Create project that contains dynamic data
  if (!Projects[DYNAMIC_DATA_PROJECT]) {
    Resources["EntityServices"].CreateProject({
      dependsOn: undefined /* STRING */,
      name: DYNAMIC_DATA_PROJECT /* STRING */,
      description: "Dynamic data for HPMC project (assets, usergroups etc.)" /* STRING */,
      type: "Component" /* STRING */,
      tags: undefined /* TAGS */
    });
  }

  // Create Core usergroup that will contain the usergroup for each HPMC module
  if (!Groups[USER_GROUP]) {
    Resources["EntityServices"].CreateGroup({
      name: USER_GROUP /* STRING */,
      description: "Core usergroup that contains the usergroup for each HPMC module." /* STRING */,
      projectName: DYNAMIC_DATA_PROJECT /* PROJECTNAME */,
      tags: undefined /* TAGS */
    });
  }
  // Create Core Thinggroup that will contain the assets & locations
  if (!ThingGroups[THING_GROUP])
    Resources["EntityServices"].CreateThingGroup({
      name: THING_GROUP /* STRING */,
      description: "Global Thing Group for all locations and their assets." /* STRING */,
      projectName: DYNAMIC_DATA_PROJECT /* PROJECTNAME */,
      tags: undefined /* TAGS */
    });
  //Create DB-Connector-Entity
  Resources["EntityServices"].CreateThing({
    name: "HPMC.Core.DBConnector" /* STRING */,
    description: "PostgreSQL Connector Entity " /* STRING */,
    thingTemplateName: "HPMC.Core.DBConnector.TT" /* THINGTEMPLATENAME */,
    projectName: DYNAMIC_DATA_PROJECT /* PROJECTNAME */,
    tags: undefined /* TAGS */
  });
  /* **************************** Set permissions for project entities **************************** */
  /* THINGS */
  addVisibilityPermission(Things, MANAGER_THING, ORGANIZATION_NAME, "Organization");
  addRunTimePermission(Things, MANAGER_THING, USER_GROUP, "*", "ServiceInvoke", "Group");
  addRunTimePermission(Things, MANAGER_THING, "System", "*", "ServiceInvoke", "User");
  addRunTimePermission(Things, MANAGER_THING, "System", "*", "PropertyRead", "User");

  addVisibilityPermission(Things, "HPMC.Core.Repository", ORGANIZATION_NAME, "Organization");
  addRunTimePermission(Things, "HPMC.Core.Repository", USER_GROUP, "*", "ServiceInvoke", "Group");
  addRunTimePermission(Things, "HPMC.Core.Repository", "System", "*", "ServiceInvoke", "User");
  const currentPaths = Things["HPMC.Core.Repository"].GetDirectoryStructure();
  createRepositoryFolder("HPMC.Core.Repository", "Assets", currentPaths);
  createRepositoryFolder("HPMC.Core.Repository", "Assets/CSVCreateFiles", currentPaths);
  createRepositoryFolder("HPMC.Core.Repository", "Assets/Images", currentPaths);
  createRepositoryFolder("HPMC.Core.Repository", "Assets/ImportTemplates", currentPaths);
  createRepositoryFolder("HPMC.Core.Repository", "MachineStatusOverview", currentPaths);
  createRepositoryFolder("HPMC.Core.Repository", "StaticScreen", currentPaths);

  /* THING TEMPLATES */
  // addVisibilityPermission(ThingTemplates, "Solutions.OEE_Production.ProductionLine.TP", ORGANIZATION_NAME, "Organization");
  addInstanceVisibilityPermission(ThingTemplates, "HPMC.Core.DBConnector.TT", ORGANIZATION_NAME + ":BUAG", "OrganizationalUnit");

  addRunTimePermission(ThingTemplates, "HPMC.Core.Location.TT", "System", "QueryImplementingThingsOptimized", "ServiceInvoke", "User");
  addRunTimePermission(ThingTemplates, "HPMC.Core.Location.TT", "System", "GetImplementingThings", "ServiceInvoke", "User");
  addRunTimePermission(ThingTemplates, "HPMC.Core.Location.TT", "System", "GetImplementingThingsWithData", "ServiceInvoke", "User");

  addInstanceRunTimePermission(ThingTemplates, "HPMC.Core.Asset.TT", "System", "*", "ServiceInvoke", "User");
  addInstanceRunTimePermission(ThingTemplates, "HPMC.Core.Asset.TT", "System", "*", "PropertyRead", "User");
  addInstanceRunTimePermission(ThingTemplates, "HPMC.Core.Asset.TT", "System", "*", "PropertyWrite", "User");
  addRunTimePermission(ThingTemplates, "HPMC.Core.Asset.TT", "System", "QueryImplementingThingsWithNamedData", "ServiceInvoke", "User");
  addRunTimePermission(ThingTemplates, "HPMC.Core.Asset.TT", "System", "QueryImplementingThingsOptimized", "ServiceInvoke", "User");

  /* RESOURCES */
  addVisibilityPermission(Resources, "CSVParserFunctions", ORGANIZATION_NAME, "Organization");
  addRunTimePermission(Resources, "CSVParserFunctions", "System", "*", "ServiceInvoke", "User");

  /* MASHUPS, STYLE DEFINITION, STYLE THEMES, DATA SHAPES, MEDIA OF PROJECT*/
  let entities = Projects[me.GetProjectName()].GetEntities();
  const entityTypeArr = ["Mashup", "DataShape", "MediaEntity", "StateDefinition", "StyleDefinition", "StyleTheme"];

  entities = Resources["InfoTableFunctions"].Query({
    t: entities /* INFOTABLE */,
    query: { filters: { type: "IN", fieldName: "type", values: entityTypeArr } } /* QUERY */
  });
  entities.rows.toArray().forEach((row) => {
    const entityType = row.type === "MediaEntity" ? MediaEntities : eval(row.type + "s");
    addVisibilityPermission(entityType, row.name, ORGANIZATION_NAME, "Organization");
    addDesignTimePermission(entityType, row.name, USER_GROUP, "Read", "Group");
  });
  /* **************************** Set permissions for system entities **************************** */
  addRunTimePermission(Subsystems, "PlatformSubsystem", USER_GROUP, "GetAllStyleDefinitions", "ServiceInvoke", "Group");
  addRunTimePermission(Subsystems, "PlatformSubsystem", USER_GROUP, "GetAllStateDefinitions", "ServiceInvoke", "Group");
  addRunTimePermission(Subsystems, "PlatformSubsystem", USER_GROUP, "GetAllStyleThemes", "ServiceInvoke", "Group");
  addVisibilityPermission(Subsystems, "PlatformSubsystem", ORGANIZATION_NAME, "Organization");

  addRunTimePermission(Resources, "RuntimeLocalizationFunctions", USER_GROUP, "*", "ServiceInvoke", "Group");
  addVisibilityPermission(Resources, "RuntimeLocalizationFunctions", ORGANIZATION_NAME, "Organization");

  addRunTimePermission(Resources, "SearchFunctions", "System", "*", "ServiceInvoke", "User");
  addVisibilityPermission(Resources, "SearchFunctions", ORGANIZATION_NAME, "Organization");

  addRunTimePermission(Resources, "InfoTableFunctions", "System", "*", "ServiceInvoke", "User");
  addVisibilityPermission(Resources, "InfoTableFunctions", ORGANIZATION_NAME, "Organization");

  addRunTimePermission(Resources, "CurrentSessionInfo", USER_GROUP, "GetGlobalSessionValues", "ServiceInvoke", "Group");
  addRunTimePermission(Resources, "CurrentSessionInfo", USER_GROUP, "GetCurrentUserExtensionProperties", "ServiceInvoke", "Group");
  addVisibilityPermission(Resources, "CurrentSessionInfo", ORGANIZATION_NAME, "Organization");
  result = true;
} catch (err) {
  logger.error(me.name + ".InitializeModule: " + err.message + " - Line#" + err.lineNumber);
  Subsystems["PlatformSubsystem"].DeleteGhostEntities({
    deleteGhostEntitiesInAllInstances: true /* BOOLEAN {"defaultValue":false} */
  });
}


/*
 * @name InitializeRoles
 * @date 01.08.2024
 * @author Marc Aurel Büttner
 * @return true on success
 */

try {
  const getGroupsByMask = (nameMask) => {
    return Resources["EntityServices"].GetEntityList({
      maxItems: undefined /* NUMBER {"defaultValue":500} */,
      nameMask: nameMask /* STRING */,
      type: "Group" /* STRING */
    });
  };

  // result: INFOTABLE dataShape: "RootEntityList"
  const allHPMCUserGroups = getGroupsByMask("HPMC*Users.UG");

  const allAdminLocationGroups = getGroupsByMask("HPMC*.Administrator.UG");

  const allSupervisorLocationGroups = getGroupsByMask("HPMC*.Supervisor.UG");

  const allOperatorLocationGroups = getGroupsByMask("HPMC*.Operator.UG");

  const allDisplayLocationGroups = getGroupsByMask("HPMC*.Display.UG");

  allHPMCUserGroups.rows.toArray().forEach((moduleGroup) => {
    // Admin Users
    if (moduleGroup.name.includes("HPMC.Core.Administration.Users.UG")) {
      allAdminLocationGroups.rows
        .toArray()
        .filter((adminGroup) => adminGroup.name.split(".").length > 3) //Filter out generic groups
        .forEach((adminGroup) => {
          Groups[moduleGroup.name].AddMember({
            member: adminGroup.name /* STRING */,
            type: "Group" /* STRING */
          });
        });
      return;
    }

    // Operator Users
    if (
      moduleGroup.name.includes("HPMC.Core.Worldmap.Users.UG") ||
      moduleGroup.name.includes("HPMC.Core.MachineOverview.Users.UG") ||
      moduleGroup.name.includes("HPMC.Core.MachineStatus.Users.UG") ||
      moduleGroup.name.includes("HPMC.Core.MachineHourlyReport.Users.UG") ||
      moduleGroup.name.includes("HPMC.Core.OperatorFeedbackForm.Users.UG")
    ) {
      allOperatorLocationGroups.rows
        .toArray()
        .filter((operatorGroup) => operatorGroup.name.split(".").length > 3) //Filter out generic groups
        .forEach((operatorGroup) => {
          Groups[moduleGroup.name].AddMember({
            member: operatorGroup.name /* STRING */,
            type: "Group" /* STRING */
          });
        });
    }

    // Supervisor Users
    allSupervisorLocationGroups.rows
      .toArray()
      .filter((supervisorGroup) => supervisorGroup.name.split(".").length > 3) //Filter out generic groups
      .forEach((supervisorGroup) => {
        Groups[moduleGroup.name].AddMember({
          member: supervisorGroup.name /* STRING */,
          type: "Group" /* STRING */
        });
      });

    // Display Users
    allDisplayLocationGroups.rows
      .toArray()
      .filter((displayGroup) => displayGroup.name.split(".").length > 3) //Filter out generic groups
      .forEach((displayGroup) => {
        Groups[moduleGroup.name].AddMember({
          member: displayGroup.name /* STRING */,
          type: "Group" /* STRING */
        });
      });
  });

  result = true;
} catch (err) {
  logger.error("Error at " + me.name + ".InitializeRoles [" + err.lineNumber + "]:" + err.message);
  result = false;
}


// Content: IMAGE

const loadImageByMachineName = () => {
    let assetImages = Things["HPMC.Core.Repository"].BrowseFileSystem({
      path: "/Assets/Images/" /* STRING */,
    });
    let image = Resources["InfoTableFunctions"].Query({
      t: assetImages /* INFOTABLE */,
      query: {
        filters: {
          type: "LIKE",
          fieldName: "name",
          value: machineName + ".%",
        },
      } /* QUERY */,
    });
    return image.length > 0 ? image[0].path + "/" + image[0].name : "";
};

if (!machineName && !path) {
  result = null;
}

if (machineName && !path) {
  const pathByName = loadImageByMachineName();
  if (pathByName) {
    result = Things[fileRepository].LoadImage({ path: pathByName /* STRING */ });
  } else {
    result = null;
  }
} 

if (path && path.substr(path.length - 1) != "/") {
  try {
    result = Things[fileRepository].LoadImage({ path: path /* STRING */ }) ;
  } catch (err) {
    result = null;
    // logger.error("Error at " + me.name + ".LoadFileRepositoryImage <"+ path + "> [" + err.lineNumber + "]:" + err.message); //file not exists

  }
  // This service serves as interlayer between a mashup and the repository entity. So that the file repository must not directly be bound to the mashup.
} 

if (path && path.substr(path.length - 1) == "/") {
  result = null;
}


/**
 * @name NextNavigationBar
 * @date 28.01.2021
 * @author Isro Syaeful Iman
 * @param currentPage(STRING)  	current page open
 * @return infotable (HPMC.Core.Container.NavigationBar.DS)
 *
 * Set Navigation Bar Data on session when next button in navigation bar clicked
 */

var result;
var loggerBeginning = "[" + me.name + ":NextNavigationBar]";
(function () {
    "use strict";
    try {
        // logger.info(loggerBeginning + " Set global session for navigation bar in master header after click next button.");
        let sessionData = Resources["CurrentSessionInfo"].GetGlobalSessionValues();
        currentPage = sessionData.currentPage;
        // table: INFOTABLE dataShape: ""
        let tempData = me.GetConfigurationTable({ tableName: "NavigationEntries" /* STRING */ });
        tempData.Sort({ name: "TileOrder", ascending: true });
        let mashupArr = [];
        tempData.rows.toArray().forEach((navigationEntry) => {
                try {
                  const _ = Things[navigationEntry.ModuleManager].description;
                } catch (err) {
                  return;
                }
            mashupArr.push(navigationEntry.TileMashupOrURL);
        }); 
        let index = mashupArr.indexOf(currentPage);
        let  curr;
        if (index === -1) {
            // curr = "HPMC.Core.Worldmap.MU";
            curr = mashupArr[0];
        } else if (index < mashupArr.length + 1) {
            curr = mashupArr[index + 1];
        } else if (index === mashupArr.length + 1) {
            curr = mashupArr[0];
        }
        Resources["CurrentSessionInfo"].SetGlobalSessionStringValue({
            name: "currentPage" /* STRING */,
            value: curr /* STRING */
        });
        result = curr;
    } catch (error) {
        logger.error(loggerBeginning + " failed to set global session for navigation bar in master header.");
    }
})();


/**
 * @name NextNavigationBar
 * @date 28.01.2021
 * @author Isro Syaeful Iman
 * @param currentPage(STRING)  	current page open
 * @return infotable
 *
 * Set Navigation Bar Data on session when next button in navigation bar clicked
 */

var result;
var loggerBeginning = "[" + me.name + ":NextNavigationBar]";
(function () {
    "use strict";
    try {
        logger.info(loggerBeginning + " Set global session for navigation bar in master header after click next button.");
        let sessionData = Resources["CurrentSessionInfo"].GetGlobalSessionValues();
        // table: INFOTABLE dataShape: ""
        let tempData = me.GetConfigurationTable({ tableName: "NavigationEntries" /* STRING */ });
        tempData.Sort({ name: "TileOrder", ascending: true });
        let mashupArr = [];
        for (let i = 0; i < tempData.length; i++) {
            let data = tempData.rows[i];
            mashupArr.push(data.TileMashupOrURL);
        }

        let index = mashupArr.indexOf(currentPage);
        if (index === -1) {
            curr = "HPMC.Core.Worldmap.MU";
        } else if (index < mashupArr.length - 1) {
            curr = mashupArr[index + 1];
        } else if (index === mashupArr.length - 1) {
            curr = mashupArr[0];
        }
        Resources["CurrentSessionInfo"].SetGlobalSessionStringValue({
            name: "currentPage" /* STRING */,
            value: curr /* STRING */
        });

        result = Resources["CurrentSessionInfo"].GetGlobalSessionValues();
    } catch (error) {
        logger.error(loggerBeginning + " failed to set global session for navigation bar in master header.");
    }
})();


/**
 * @name PrevNavigationBar
 * @date 28.01.2021
 * @author Isro Syaeful Iman
 * @param currentPage(STRING)  	current page open
 * @return infotable
 *
 * Set Navigation Bar Data on session when prev button in navigation bar clicked
 */
var result;
var loggerBeginning = "[" + me.name + ":PrevNavigationBar]";
(function () {
    "use strict";
    try {
        // logger.info(loggerBeginning + " Set global session for navigation bar in master header after prev button clicked");
        let sessionData = Resources["CurrentSessionInfo"].GetGlobalSessionValues();
        currentPage = sessionData.currentPage;
        // table: INFOTABLE dataShape: ""
        let tempData = me.GetConfigurationTable({ tableName: "NavigationEntries" /* STRING */ });
        tempData.Sort({ name: "TileOrder", ascending: true });
        let mashupArr = [];
        tempData.rows.toArray().forEach((data) => {
            try {
                const _ = Things[data.ModuleManager].description;
            } catch (err) {
                return;
            }
            mashupArr.push(data.TileMashupOrURL);
        });

        let index = mashupArr.indexOf(currentPage);
        let prev, curr, next;
        let maxScreenIndex = mashupArr.length - 1;
        if (index === -1) {
            curr = mashupArr[0];
        } else if (index > 0) {
            curr = mashupArr[index - 1];
        } else if (index === 0) {
            curr = mashupArr[maxScreenIndex];
        }

        Resources["CurrentSessionInfo"].SetGlobalSessionStringValue({
            name: "currentPage" /* STRING */,
            value: curr /* STRING */
        });

        result = curr;
    } catch (error) {
        logger.error(loggerBeginning + " failed to set global session for navigation bar in master header.");
    }
})();


