/*
 * @name SetUserLanguage
 * @date 20.01.2020
 * @author Isro Syaeful Iman CAD-IT
 * @param username (USERNAME)	username of user
 * @param languageCode (STRING)	language code
 * @return BOOLEAN
 *
 * [COMPLETED] Set User Language
 */
var result;
var loggerBeginning = "[" + me.name + ":SetUserLanguage]";
(function () {
    "use strict";
    try {
        if (languageCode !== Users[username].language && languageCode !== undefined) {
            Users[username].language = languageCode;
            result = true;
        } else {
            result = false;
        }
    } catch (error) {
        result = false;
        logger.error(loggerBeginning + " failed to set user language - [ERROR] " + error);
    }
})();
